(function () {
    function closeDropdowns(except) {
        document.querySelectorAll(".dropdown-menu.show").forEach(function (menu) {
            if (menu !== except) {
                menu.classList.remove("show");
            }
        });
        document.querySelectorAll('[data-bs-toggle="dropdown"][aria-expanded="true"]').forEach(function (toggle) {
            if (!except || toggle.nextElementSibling !== except) {
                toggle.setAttribute("aria-expanded", "false");
            }
        });
    }

    function Modal(element) {
        this.element = element;
    }

    Modal.prototype.show = function () {
        if (!this.element) return;
        this.element.classList.add("show");
        this.element.style.display = "block";
        this.element.removeAttribute("aria-hidden");
        this.element.setAttribute("aria-modal", "true");
        document.body.classList.add("modal-open");

        var backdrop = document.createElement("div");
        backdrop.className = "modal-backdrop fade show";
        backdrop.setAttribute("data-local-backdrop-for", this.element.id || "");
        document.body.appendChild(backdrop);
    };

    Modal.prototype.hide = function () {
        if (!this.element) return;
        this.element.classList.remove("show");
        this.element.style.display = "none";
        this.element.setAttribute("aria-hidden", "true");
        this.element.removeAttribute("aria-modal");
        document.body.classList.remove("modal-open");

        document.querySelectorAll(".modal-backdrop").forEach(function (backdrop) {
            backdrop.remove();
        });
    };

    document.addEventListener("click", function (event) {
        var dropdownToggle = event.target.closest('[data-bs-toggle="dropdown"]');
        if (dropdownToggle) {
            event.preventDefault();
            var menu = dropdownToggle.nextElementSibling;
            if (menu && menu.classList.contains("dropdown-menu")) {
                var willShow = !menu.classList.contains("show");
                closeDropdowns(menu);
                menu.classList.toggle("show", willShow);
                dropdownToggle.setAttribute("aria-expanded", willShow ? "true" : "false");
            }
            return;
        }

        var dismissButton = event.target.closest('[data-bs-dismiss="modal"]');
        if (dismissButton) {
            var modalElement = dismissButton.closest(".modal");
            if (modalElement) {
                new Modal(modalElement).hide();
            }
            return;
        }

        if (!event.target.closest(".dropdown")) {
            closeDropdowns();
        }
    });

    document.addEventListener("keydown", function (event) {
        if (event.key === "Escape") {
            document.querySelectorAll(".modal.show").forEach(function (modalElement) {
                new Modal(modalElement).hide();
            });
            closeDropdowns();
        }
    });

    window.bootstrap = window.bootstrap || {};
    window.bootstrap.Modal = Modal;
})();
